/* greenboost_cuda.map — GNU ld version script
 *
 * Applications link against versioned CUDA symbols:
 *   cudaMalloc@libcudart.so.12   — CUDA 12.x (system libcudart, llama.cpp)
 *   cudaMalloc@libcudart.so.13   — CUDA 13.x (Ollama bundled)
 *
 * Unversioned exports from LD_PRELOAD do NOT satisfy versioned requirements.
 * We must export our hooks under the exact version strings callers require.
 *
 * Both libcudart.so.12 and .13 are provided for compatibility.
 */

libcudart.so.12 {
    global:
        cudaMalloc;
        cudaMallocAsync;
        cudaFree;
        cudaMemGetInfo;
        cudaMallocManaged;
        cudaMemPrefetchAsync;
};

libcudart.so.13 {
    global:
        cudaMalloc;
        cudaMallocAsync;
        cudaFree;
        cudaMemGetInfo;
        cudaMallocManaged;
        cudaMemPrefetchAsync;
};

GLIBC_2.2.5 {
    global:
        dlopen;
        dlsym;
};

GLIBC_2.34 {
    global:
        dlopen;
        dlsym;
};
